{ title: "Inchecken in een hotel op Rhodos", scene: "Je komt aan bij een hotel op Rhodos. Je hebt een reservering en vraagt naar ontbijt en je kamer.", lines: [{ who: "them", el: "Καλησπέρα σας.", nl: "Goedenavond." }, { who: "you", el: "Καλησπέρα, έχω κράτηση.", nl: "Goedenavond, ik heb een reservering." }, { who: "them", el: "Το όνομά σας, παρακαλώ;", nl: "Uw naam, alstublieft?" }, { who: "you", el: "Με λένε Γιάννη Κάνον.", nl: "Ik heet Jimmy Cannon." }, { who: "them", el: "Το διαβατήριό σας, παρακαλώ.", nl: "Uw paspoort, alstublieft." }, { who: "you", el: "Ορίστε το διαβατήριό μου.", nl: "Hier is mijn paspoort." }, { who: "them", el: "Το δωμάτιό σας είναι στον δεύτερο όροφο.", nl: "Uw kamer is op de tweede verdieping." }, { who: "you", el: "Πού είναι το ασανσέρ;", nl: "Waar is de lift?" }, { who: "them", el: "Είναι δεξιά.", nl: "Die is rechts." }, { who: "you", el: "Τι ώρα είναι το πρωινό;", nl: "Hoe laat is het ontbijt?" }, { who: "them", el: "Από τις επτά μέχρι τις δέκα.", nl: "Van zeven tot tien." }, { who: "you", el: "Ευχαριστώ για τη βοήθεια.", nl: "Bedankt voor de hulp." }] },
{ title: "De weg vragen naar de Akropolis", scene: "Je bent in Athene en wilt naar de Akropolis lopen. Je vraagt een voorbijganger om eenvoudige aanwijzingen.", lines: [{ who: "you", el: "Συγγνώμη, πού είναι η Ακρόπολη;", nl: "Pardon, waar is de Akropolis?" }, { who: "them", el: "Είναι κοντά από εδώ.", nl: "Het is dichtbij vanaf hier." }, { who: "you", el: "Πώς πάω εκεί;", nl: "Hoe kom ik daar?" }, { who: "them", el: "Πηγαίνετε ευθεία.", nl: "Ga rechtdoor." }, { who: "you", el: "Μετά στρίβω δεξιά;", nl: "Daarna sla ik rechtsaf?" }, { who: "them", el: "Όχι, στρίψτε αριστερά στην πλατεία.", nl: "Nee, sla linksaf bij het plein." }, { who: "you", el: "Είναι μακριά;", nl: "Is het ver?" }, { who: "them", el: "Όχι, δέκα λεπτά με τα πόδια.", nl: "Nee, tien minuten lopen." }, { who: "you", el: "Ευχαριστώ πολύ.", nl: "Heel erg bedankt." }, { who: "them", el: "Παρακαλώ, καλή βόλτα.", nl: "Graag gedaan, fijne wandeling." }, { who: "you", el: "Καλή συνέχεια.", nl: "Het ga u goed." }] },
{ title: "Eten in een taverna op Kreta", scene: "Je zit in een taverna aan zee op Kreta. Je vraagt om een aanbeveling en bestelt een eenvoudige maaltijd.", lines: [{ who: "them", el: "Καλησπέρα, έχετε κράτηση;", nl: "Goedenavond, heeft u een reservering?" }, { who: "you", el: "Όχι, έχετε διαθέσιμο τραπέζι;", nl: "Nee, heeft u een tafel beschikbaar?" }, { who: "them", el: "Ναι, για πόσα άτομα;", nl: "Ja, voor hoeveel personen?" }, { who: "you", el: "Για δύο άτομα.", nl: "Voor twee personen." }, { who: "them", el: "Ορίστε το μενού.", nl: "Hier is het menu." }, { who: "you", el: "Τι προτείνετε;", nl: "Wat raadt u aan?" }, { who: "them", el: "Το ψάρι είναι πολύ φρέσκο σήμερα.", nl: "De vis is vandaag erg vers." }, { who: "you", el: "Ωραία, θέλω ψάρι και σαλάτα.", nl: "Mooi, ik wil vis en salade." }, { who: "them", el: "Θέλετε τοπικό κρασί;", nl: "Wilt u lokale wijn?" }, { who: "you", el: "Ναι, ένα ποτήρι, παρακαλώ.", nl: "Ja, één glas, alstublieft." }, { who: "them", el: "Βεβαίως.", nl: "Natuurlijk." }, { who: "you", el: "Ευχαριστώ πολύ.", nl: "Heel erg bedankt." }] },
{ title: "Metrokaartjes kopen in Athene", scene: "Je bent in een metrostation in Athene. Je wilt naar Piraeus en vraagt welk ticket en welke lijn je nodig hebt.", lines: [{ who: "them", el: "Γεια σας, πώς μπορώ να βοηθήσω;", nl: "Hallo, hoe kan ik helpen?" }, { who: "you", el: "Θέλω ένα εισιτήριο για τον Πειραιά.", nl: "Ik wil een ticket naar Piraeus." }, { who: "them", el: "Θέλετε μονό εισιτήριο;", nl: "Wilt u een enkeltje?" }, { who: "you", el: "Ναι, ένα μονό εισιτήριο.", nl: "Ja, één enkeltje." }, { who: "them", el: "Δύο ευρώ, παρακαλώ.", nl: "Twee euro, alstublieft." }, { who: "you", el: "Ορίστε. Ποια γραμμή πάει στον Πειραιά;", nl: "Alstublieft. Welke lijn gaat naar Piraeus?" }, { who: "them", el: "Η πράσινη γραμμή.", nl: "De groene lijn." }, { who: "you", el: "Πρέπει να αλλάξω;", nl: "Moet ik overstappen?" }, { who: "them", el: "Όχι, πηγαίνετε απευθείας.", nl: "Nee, u gaat rechtstreeks." }, { who: "you", el: "Πού είναι η αποβάθρα;", nl: "Waar is het perron?" }, { who: "them", el: "Κάτω και δεξιά.", nl: "Beneden en rechts." }, { who: "you", el: "Ευχαριστώ.", nl: "Dank u." }] },
{ title: "Souvenirs kopen in een winkel", scene: "Je bent in een kleine souvenirwinkel op Santorini. Je zoekt een klein cadeau en vraagt naar prijs en kleur.", lines: [{ who: "them", el: "Καλημέρα, μπορώ να βοηθήσω;", nl: "Goedemorgen, kan ik helpen?" }, { who: "you", el: "Ναι, θέλω ένα μικρό δώρο.", nl: "Ja, ik wil een klein cadeau." }, { who: "them", el: "Έχουμε αυτά τα σουβενίρ.", nl: "We hebben deze souvenirs." }, { who: "you", el: "Μου αρέσει το μπλε.", nl: "Ik vind blauw mooi." }, { who: "them", el: "Αυτό είναι πολύ ωραίο.", nl: "Dit is erg mooi." }, { who: "you", el: "Πόσο κοστίζει αυτό;", nl: "Hoeveel kost dit?" }, { who: "them", el: "Κάνει οκτώ ευρώ.", nl: "Het kost acht euro." }, { who: "you", el: "Μπορώ να το δω;", nl: "Kan ik het zien?" }, { who: "them", el: "Βεβαίως.", nl: "Natuurlijk." }, { who: "you", el: "Θα το πάρω.", nl: "Ik neem het." }, { who: "them", el: "Θέλετε σακούλα;", nl: "Wilt u een zakje?" }, { who: "you", el: "Ναι, παρακαλώ.", nl: "Ja, alstublieft." }] },
{ title: "Bij de apotheek voor hoofdpijn", scene: "Je hebt hoofdpijn na een warme dag in Heraklion. Je gaat naar een apotheek en vraagt om hulp.", lines: [{ who: "them", el: "Καλησπέρα σας.", nl: "Goedenavond." }, { who: "you", el: "Καλησπέρα, έχω πονοκέφαλο.", nl: "Goedenavond, ik heb hoofdpijn." }, { who: "them", el: "Έχετε πυρετό;", nl: "Heeft u koorts?" }, { who: "you", el: "Όχι, δεν έχω πυρετό.", nl: "Nee, ik heb geen koorts." }, { who: "them", el: "Έχετε αλλεργία σε φάρμακα;", nl: "Bent u allergisch voor medicijnen?" }, { who: "you", el: "Όχι, δεν έχω αλλεργία.", nl: "Nee, ik heb geen allergie." }, { who: "them", el: "Χρειάζεστε αυτό το φάρμακο.", nl: "U heeft dit medicijn nodig." }, { who: "you", el: "Πώς το παίρνω;", nl: "Hoe neem ik het?" }, { who: "them", el: "Με νερό, μετά το φαγητό.", nl: "Met water, na het eten." }, { who: "you", el: "Ευχαριστώ πολύ.", nl: "Heel erg bedankt." }, { who: "them", el: "Περαστικά σας.", nl: "Beterschap." }, { who: "you", el: "Ευχαριστώ, καλή συνέχεια.", nl: "Dank u, het ga u goed." }] },
{ title: "Smalltalk met een lokale bewoner", scene: "Je zit op een bankje bij de haven van Naxos. Een lokale bewoner begint vriendelijk te praten en je probeert eenvoudig Grieks te gebruiken.", lines: [{ who: "you", el: "Καλησπέρα σας.", nl: "Goedenavond." }, { who: "them", el: "Καλησπέρα, από πού είστε;", nl: "Goedenavond, waar komt u vandaan?" }, { who: "you", el: "Είμαι από την Ολλανδία.", nl: "Ik kom uit Nederland." }, { who: "them", el: "Μιλάτε ελληνικά;", nl: "Spreekt u Grieks?" }, { who: "you", el: "Μιλάω λίγο ελληνικά.", nl: "Ik spreek een beetje Grieks." }, { who: "them", el: "Πολύ ωραία. Σας αρέσει η Νάξος;", nl: "Heel mooi. Vindt u Naxos leuk?" }, { who: "you", el: "Ναι, μου αρέσει πολύ.", nl: "Ja, ik vind het erg leuk." }, { who: "them", el: "Η θάλασσα είναι όμορφη σήμερα.", nl: "De zee is vandaag mooi." }, { who: "you", el: "Ναι, και ο καιρός είναι καλός.", nl: "Ja, en het weer is goed." }, { who: "them", el: "Είστε εδώ για διακοπές;", nl: "Bent u hier op vakantie?" }, { who: "you", el: "Ναι, και θέλω να επιστρέψω.", nl: "Ja, en ik wil terugkomen." }, { who: "them", el: "Καλή συνέχεια και καλό ταξίδι.", nl: "Het ga u goed en goede reis." }] }
